demos.desktop:
render(() => {
    const [disabled, setDisabled] = React.useState(false);

    return (
        <Container>
            <Row align='middle'>
                <FilterTag size={32} checked={false} disabled={disabled}>
                    <span>Label</span>
                </FilterTag>
                <Gap size={12} direction='horizontal' />
                <FilterTag size={32} checked={true} disabled={disabled}>
                    {disabled ? (
                        <span>Label</span>
                    ) : (
                        <span>
                            Label:<b> Value</b>
                        </span>
                    )}
                </FilterTag>
            </Row>
            <Gap size={24} />
            <Switch
                label='Недоступно'
                checked={disabled}
                onChange={() => setDisabled((prevState) => !prevState)}
            />
        </Container>
    );
});

render(() => {
    const [leftAddons, setLeftAddons] = React.useState(true);
    const [selected, setSelected] = React.useState(false);

    const addon = () => {
        if (leftAddons) {
            return (
                <div
                    style={{
                        width: 16,
                        height: 16,
                        backgroundColor: 'var(--color-light-status-muted-alt-info)',
                        border: '1px dashed var(--color-light-status-info)',
                        borderRadius: '4px',
                    }}
                />
            );
        }

        return null;
    };

    return (
        <Container>
            <FilterTag size={32} checked={selected} leftAddons={addon()}>
                {selected ? (
                    <span>
                        Label:<b> Value</b>
                    </span>
                ) : (
                    <span>Label</span>
                )}
            </FilterTag>
            <Gap size={24} />
            <Switch
                label='LeftAddon'
                checked={leftAddons}
                onChange={() => setLeftAddons((prevState) => !prevState)}
            />
            <Gap size={16} />
            <Switch
                label='Selected'
                checked={selected}
                onChange={() => setSelected((prevState) => !prevState)}
            />
        </Container>
    );
});
